draw(U--V--D--cycle);
F=D+U;
EE=(V+F)/2;
G=flip(U,V)*F;
H=flip(U,V)*F;
A=extension(E,F,U,V);
B=extension(F,G,U,V);
C=extension(E,G,D,V);
W=polar(U,abs(H));
W=D+dir(180)*W.x;
W=rotate(90)*(W);
draw(U--D--EE--cycle);
label("$\bf U$",U,N);
label("$\bf V$",V,S);
label("$\bf W$",W+E,NE);
[/asy]
